**Spring Boot CQRS implementation:**

```java
// COMMAND:
public record PlaceOrderCommand(String merchantId, String symbol,
    int quantity, OrderType type) {}

// COMMAND HANDLER:
@Service
public class OrderCommandHandler {
    @Transactional
    public OrderId handle(PlaceOrderCommand cmd) {
        // Validate + persist + emit event:
        Order order = new Order(cmd.merchantId(), cmd.symbol(), cmd.quantity(), cmd.type());
        repo.save(order);
        eventBus.publish(new OrderPlacedEvent(order.getId(), cmd.symbol(), cmd.quantity()));
        return order.getId();
    }
}

// QUERY:
public record GetPortfolioQuery(String merchantId) {}

// QUERY HANDLER (reads from denormalized view):
@Service
public class PortfolioQueryHandler {
    public PortfolioView handle(GetPortfolioQuery query) {
        return portfolioViewRepo.findByMerchantId(query.merchantId())
            .orElse(PortfolioView.empty(query.merchantId()));
    }
}

// PROJECTION (keeps read model in sync):
@Service
public class PortfolioProjection {
    @EventListener
    @Async  // don't block the command handler
    public void on(OrderFilledEvent event) {
        // Update pre-calculated portfolio view:
        portfolioViewRepo.updatePosition(event.merchantId(), event.symbol(),
            event.quantity(), event.price());
    }
}
```

